questions.starterCode:
#include <stdio.h>

int main() {
    double celsius;
    scanf("%lf", &celsius);
    // Your code here
    return 0;
}

questions.solution:
#include <stdio.h>

int main() {
    double celsius, fahrenheit;
    scanf("%lf", &celsius);
    fahrenheit = (celsius * 9.0 / 5.0) + 32.0;
    printf("%.2lf", fahrenheit);
    return 0;
}

questions.starterCode:
#include <stdio.h>

int main() {
    double p, r, t;
    scanf("%lf %lf %lf", &p, &r, &t);
    // Your code here
    return 0;
}

questions.solution:
#include <stdio.h>

int main() {
    double p, r, t, si, amount;
    scanf("%lf %lf %lf", &p, &r, &t);
    si = (p * r * t) / 100.0;
    amount = p + si;
    printf("%.2lf\n%.2lf", si, amount);
    return 0;
}
